import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,u as c}from"./app-NcQGaZV0.js";var l=JSON.parse(`{"path":"/posts/angular-21.html","title":"Angular 21(.1 !)","lang":"fr-FR","frontmatter":{"date":"2026-01-21T00:00:00.000Z","category":["Veille"],"tag":["Angular"]},"git":{"updatedTime":1769160293000,"contributors":[{"name":"Anthony Lenglet","username":"","email":"anthony.lenglet@hotmail.com","commits":1}],"changelog":[{"hash":"9d9e78f84e5bffbf70ade72e891a708abd764375","time":1769160293000,"email":"anthony.lenglet@hotmail.com","author":"Anthony Lenglet","message":"new post: <code>angular-21.md</code>"}]},"filePathRelative":"posts/angular-21.md","excerpt":"\\n<p>Sonnez les cloches, ouvrez les fenêtres, dégivrez de nouveau Mariah Carey parce que</p>\\n<figure><img src=\\"/assets/posts/angular-21/its-time.gif\\" alt=\\"Mariah Carey screaming &quot;It's Time !&quot;\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>Alternativement: il est l'or monseignor !</figcaption></figure>"}`),u={name:`angular-21.md`};function d(i,l,u,d,f,p){let m=r(`RouteLink`);return t(),n(`div`,null,[l[3]||=e(`<h1 id="angular-21-1" tabindex="-1"><a class="header-anchor" href="#angular-21-1"><span>Angular 21(.1 !)</span></a></h1><p>Sonnez les cloches, ouvrez les fenêtres, dégivrez de nouveau Mariah Carey parce que</p><figure><img src="/assets/posts/angular-21/its-time.gif" alt="Mariah Carey screaming &quot;It&#39;s Time !&quot;" tabindex="0" loading="lazy"><figcaption>Alternativement: il est l&#39;or monseignor !</figcaption></figure><p>On a une nouvelle version d&#39;Angular, et il y a des choses assez cool à voir, dont une annonce particulièrement intéressante que je nous garde pour la fin !</p><p>Bon en vrai cet article ne sera pas que sur des nouveautés de la version 21, vu qu&#39;on est en train de construire sur des bases auxquels vous n&#39;êtes pas forcément familier si vous n&#39;avez pas touché au nouvelles features des 3/4 dernières versions, mais promis je reste concis cette fois !</p><p>Depuis le temps, je pense que vous en avait entendu parler, mais au cas ou, faisont un petit détour par une courte présentation des signals, histoire d&#39;être sur d&#39;être tous à la même page</p><h2 id="les-signals" tabindex="-1"><a class="header-anchor" href="#les-signals"><span>Les signals</span></a></h2><p>Pour faire cours Les signals sont un conteneur pour une valeur qui notifie les composants l&#39;utilisant quand la valeur est mise à jour.</p><p>Alors la vous vous dites probablement &quot;mais attend, c&#39;est pas des observables du coup ?&quot;, ce à quoi je vous réponds que plus ou moins oui !</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">ExampleComponent</span> <span class="token punctuation">{</span></span>
<span class="line">  firstValue <span class="token operator">=</span> <span class="token function">signal</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  secondValue <span class="token operator">=</span> <span class="token function">signal</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  result <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">Number</span><span class="token punctuation">(</span>firstValue<span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token function">Number</span><span class="token punctuation">(</span>secondValue<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token function">incrementFirstValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    firstValue<span class="token punctuation">.</span><span class="token function">update</span><span class="token punctuation">(</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">Number</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>label</span> <span class="token attr-name">for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>first<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Enter the first value:<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>label</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>first<span class="token punctuation">&quot;</span></span> <span class="token attr-name">[(ngModel)]</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>firstValue<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">(click)</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>incrementFirstValue()<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Increment first value<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>label</span> <span class="token attr-name">for</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>second<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Enter the second value:<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>label</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>second<span class="token punctuation">&quot;</span></span> <span class="token attr-name">[(ngModel)]</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>secondValue<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span><span class="token punctuation">&gt;</span></span>result: {{count}}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Pour la large majorité des cas, ce qui est historiquement fait avec des observable dans Angular peux être traduit assez simplement en signals, et le code qui en ressort est beaucoup plus lisible, notament dû au fait que la totalité des modifications normalement effectué dans la fonction <code>pipe()</code> sont remplacé par une seule fonction <code>computed()</code>, qui écoute automatiquement tous les signals utilisé dans la fonction pour des changements et relance la fonction dès qu&#39;elle en détecte une !</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">const</span> observableExample <span class="token operator">=</span> <span class="token keyword">of</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">,</span><span class="token number">6</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">5</span><span class="token punctuation">,</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">.</span><span class="token function">pipe</span><span class="token punctuation">(</span></span>
<span class="line">    <span class="token function">map</span><span class="token punctuation">(</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token keyword">return</span> value<span class="token punctuation">.</span><span class="token function">sort</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">subscribe</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> signalsExample <span class="token operator">=</span> <span class="token function">signal</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">,</span><span class="token number">6</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">5</span><span class="token punctuation">,</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">const</span> computedExample <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> signalsExample<span class="token punctuation">.</span><span class="token function">sort</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Les valeurs des observables sont toujours envoyé dans une liste, d&#39;ou le fait qu&#39;on ai besoin de passer par un map pour acceder à notre valeur, ce qui n&#39;est plus le cas avec les signals !</p><div class="hint-container info"><p class="hint-container-title">Info</p><p>il existe aussi <code>effect()</code>, qui est comme <code>computed()</code>, à la difference qu&#39;il ne resort pas de valeur, à utiliser lorsque vous voulez juste lancer une fonction en réponse à un changement de valeur !</p></div><p>Globalement, il faut juste ce dire que le plan long terme d&#39;Angular et de ne garder les observables que pour les cas super complexe qui demande vraiment l&#39;utilisation d&#39;un observable (ouvrir un canal d&#39;informations qui arriverons dans le temps, et pouvoir planifier le filtrage en amont ainsi que la façon dont l&#39;information est partagé au reste de l&#39;application) Côté Angular natif, cela signifie qu&#39;à long terme, les observable seront limité aux retour de requête HTTP et les formulaires complexe, et justement, en parlant des formulaires...</p><h2 id="les-formulaires-signals" tabindex="-1"><a class="header-anchor" href="#les-formulaires-signals"><span>Les formulaires signals</span></a></h2><p>Pour les formulaire de tout les jours, voici maintenant une façon plus simple (et censé) de faire un formulaire avec typage et validations !</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> Component<span class="token punctuation">,</span> signal <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@angular/core&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> FormField<span class="token punctuation">,</span> form<span class="token punctuation">,</span> email<span class="token punctuation">,</span> required <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@angular/forms/signals&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">interface</span> <span class="token class-name">LoginData</span> <span class="token punctuation">{</span></span>
<span class="line">  email<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line">  password<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token decorator"><span class="token at operator">@</span><span class="token function">Component</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  imports<span class="token operator">:</span> <span class="token punctuation">[</span>FormField<span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">  template<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string"></span>
<span class="line">    Email: &lt;input [formField]=&quot;loginForm.email&quot;&gt;</span>
<span class="line">    Password: &lt;input [formField]=&quot;loginForm.password&quot;&gt;</span>
<span class="line">  </span><span class="token template-punctuation string">\`</span></span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">LoginForm</span> <span class="token punctuation">{</span></span>
<span class="line">  login <span class="token operator">=</span> <span class="token generic-function"><span class="token function">signal</span><span class="token generic class-name"><span class="token operator">&lt;</span>LoginData<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">    email<span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    password<span class="token operator">:</span> <span class="token string">&#39;&#39;</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  </span>
<span class="line">  loginForm <span class="token operator">=</span> <span class="token function">form</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>login<span class="token punctuation">,</span> <span class="token punctuation">(</span>schemaPath<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">required</span><span class="token punctuation">(</span>schemaPath<span class="token punctuation">.</span>email<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token function">email</span><span class="token punctuation">(</span>schemaPath<span class="token punctuation">.</span>email<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>La nouvelle fonction <code>form()</code> prend un signal, représentant son format, ainsi une fonction supplémentaire optionelle (qui reçois un <code>schemaPath</code> contenant le chemin vers les valeurs du formulaire) permettant de configurer la validation des champs individuel !</p><p>Dorénavant, la création de mécanisme de validation customisé sera beaucoup plus simple, et le typage deviens juste une interface classique sans besoin de penser à <code>FormControl</code> ou <code>FormGroup</code> !</p><h2 id="bye-bye-zone-js" tabindex="-1"><a class="header-anchor" href="#bye-bye-zone-js"><span>Bye bye zone.js</span></a></h2><p>Poussé vers la sortie depuis Angular 18, Angular 21 sonne le glas pour Zone.js</p><p>Pour les personnes qui ne savent pas vraiment ce que faisait Zone.js dans vos applications, c&#39;était une librairie ayant pour but de detecter tout les changements côté code js qui pourrais affecter de prêt ou de loin le rendus de l&#39;interface et de lancer un redessinage de la page dans ce cas, afin de s&#39;assurer que l&#39;interface et le code reste synchro</p><p>Typiquement, sans Zone.js, ce compteur ne se metterais pas à jour visuellement:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token decorator"><span class="token at operator">@</span><span class="token function">Component</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  selector<span class="token operator">:</span> <span class="token string">&#39;app-root&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  template<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string"></span>
<span class="line">    &lt;button (click)=&quot;updateCounter()&quot;&gt;Click me&lt;/button&gt;</span>
<span class="line">    &lt;p&gt;{{counter}}&lt;/p&gt;</span>
<span class="line">  </span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AppComponent</span> <span class="token punctuation">{</span></span>
<span class="line">  counter <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token function">updateCounter</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>counter<span class="token operator">++</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mais bien sur, cela ne venais pas sans aucun drawback, notament le fait que les Zone.js à tendance à surfaire le travail ainsi qu&#39;a apporter son lot de problème de performance (suivre non-stop les valeurs de toutes les variables de l&#39;application + les requêtes html + les évènements utilisateurs + les timers js peux avoir tendance à faire ça effectivement)</p><p>Initialement, il avais été considéré comme un bon tradeoff à avoir, mais au fil du temps (et notament avec les signals), il à été décidé que se débarrasser de Zone.js était le bon choix</p><p>dorénavant, il vous faudra faire usage des signals pour cet example !</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token decorator"><span class="token at operator">@</span><span class="token function">Component</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">  selector<span class="token operator">:</span> <span class="token string">&#39;app-root&#39;</span><span class="token punctuation">,</span></span>
<span class="line">  template<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string"></span>
<span class="line">    &lt;button (click)=&quot;updateCounter()&quot;&gt;Click me&lt;/button&gt;</span>
<span class="line">    &lt;p&gt;{{counter}}&lt;/p&gt;</span>
<span class="line">  </span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AppComponent</span> <span class="token punctuation">{</span></span>
<span class="line">  counter <span class="token operator">=</span> <span class="token function">signal</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token function">updateCounter</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">this</span><span class="token punctuation">.</span>counter<span class="token punctuation">.</span><span class="token function">update</span><span class="token punctuation">(</span>value <span class="token operator">=&gt;</span> value<span class="token operator">++</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="vitest-par-defaut" tabindex="-1"><a class="header-anchor" href="#vitest-par-defaut"><span>Vitest par défaut</span></a></h2><p>Les outils de tests côté Angular ont toujours été un point faible, et nombreux sont les personnes qui remplaçais Karma et Jasmine par une alternative tel de Jest et Cypress</p><p>Avec Angular 21, tout ça change enfin, parce que Vitest deviens le framework de choix par défaut des nouvelles applications Angular, et un outil de migration est rendu disponible pour les anciennes apps</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">ng g @schematics/angular:refactor-jasmine-vitest</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Merci pour les travaux, Jasmine et Karma, maintenant on peux partir de l&#39;avant avec des outils moderne !</p><h2 id="angular-aria" tabindex="-1"><a class="header-anchor" href="#angular-aria"><span>Angular Aria</span></a></h2><p>Le meilleur pour la fin !</p><p><a href="https://angular.dev/guide/aria/overview" target="_blank" rel="noopener noreferrer">Angular Aria</a> est une nouvelle librairie de composant headless faite par l&#39;équipe d&#39;angular pour les applications ayant besoin de leur propre design systems</p>`,38),o(`p`,null,[l[1]||=a(`Vu que je suis un Oracle apparemment, je ne peux que vous conseiller `),s(m,{to:`/posts/headless-ui-library.html`},{default:c(()=>l[0]||=[a(`mon premier article sur ce blog`)]),_:1,__:[0]}),l[2]||=a(`, qui présente en profondeur ce sujet (et aussi pour des examples concret de composant)`)]),l[4]||=e(`<p>Retenez juste que à partir de maintenant, le meilleurs moyen de développer des composants est en partant de ces composants non stylisé, car ils gèrent la totalité des demandes d’accessibilité pour vous, et seront toujours mis à jour vis à vis de la dernière version d&#39;Angular, le tout sans contrepartie !</p><p>Les composants actuellement disponibles sont:</p><ul><li>Les Accordéons</li></ul><figure><img src="/assets/posts/angular-21/accordion.png" alt="Un example d’élément accordéon" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément accordéon</figcaption></figure><ul><li>Les Combobox (combo input + popup)</li></ul><figure><img src="/assets/posts/angular-21/combobox.png" alt="Un example d’élément combobox" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément combobox</figcaption></figure><ul><li>Les Grilles (utile en tant que base pour des grilles avec cases à taille variable, version plus complexe des élément <code>&lt;table&gt;</code>, ou alors un calendrier)</li></ul><figure><img src="/assets/posts/angular-21/grid.gif" alt="Un example d’élément grille (avec la navigation clavier déjà géré !)" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément grille (avec la navigation clavier déjà géré !)</figcaption></figure><ul><li>Les listbox</li></ul><figure><img src="/assets/posts/angular-21/listbox.png" alt="Un example d’élément listbox" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément listbox</figcaption></figure><ul><li>Les menus déroulants</li></ul><figure><img src="/assets/posts/angular-21/menu.png" alt="Un example d’élément menu" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément menu</figcaption></figure><ul><li>Les tabs</li></ul><figure><img src="/assets/posts/angular-21/tabs.png" alt="Un example d’élément tabs" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément tabs</figcaption></figure><ul><li>Les toolbars</li></ul><figure><img src="/assets/posts/angular-21/toolbar.png" alt="Un example d’élément toolbar" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément toolbar</figcaption></figure><ul><li>Les Arborescences</li></ul><figure><img src="/assets/posts/angular-21/tree.png" alt="Un example d’élément arborescences" width="300" tabindex="0" loading="lazy"><figcaption>Un example d’élément arborescences</figcaption></figure><p>Plus besoin d&#39;une librairie externe pour ces composants, et ça va continuer à arriver !</p><figure><img src="/assets/posts/angular-21/yipee.gif" alt="🎉🎉🎉" tabindex="0" loading="lazy"><figcaption>🎉🎉🎉</figcaption></figure><h2 id="a-venir-les-ameliorations-du-compilateur-de-template" tabindex="-1"><a class="header-anchor" href="#a-venir-les-ameliorations-du-compilateur-de-template"><span>A venir: les améliorations du compilateur de template</span></a></h2><p>Avec Angular 21.1 et .2 sur la route, les changements qui commencent à sortir laisse suggérer un focus sur le compilateur de template, avec l&#39;ajout du supports pour plusieurs syntaxes javascript (opérateurs spread, instanceof, fonctions fléchées); est-ce que c&#39;est juste un petit sujet de pasage, ou est-ce signe d&#39;un plus gros focus sur le mix du code js et du code template dans le même fichier ? Cela reste à voir, mais de mon côté, je restes au aguets !</p><p>Bon, c&#39;est pas tout ça, mais j&#39;ai des mises à jour à faire, et un 5ème element select à faire, du coup je vais vous laisser avec les premiers croquis de la potentielle nouvelle mascotte d&#39;angular ! soyez gentil avec lui, et ne lui faites pas peur, je compte sur vous !</p><figure><img src="/assets/posts/angular-21/angular-mascot.png" alt="Croquis de la nouvelle mascotte Angular" tabindex="0" loading="lazy"><figcaption>Croquis de la nouvelle mascotte Angular</figcaption></figure>`,24)])}var f=i(u,[[`render`,d]]);export{l as _pageData,f as default};